def token_f1(a, b):
    # compute token F1 with counts (multiset)
    ta = a.split()
    tb = b.split()
    # min count per token
    from collections import Counter
    ca, cb = Counter(ta), Counter(tb)
    overlap = sum(min(ca[t], cb[t]) for t in set(ca)|set(cb))
    if overlap == 0:
        return 0.0
    prec = overlap / len(tb)
    rec  = overlap / len(ta)
    if prec+rec == 0:
        return 0.0
    return 2 * prec * rec / (prec + rec)

